const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamodb = new AWS.DynamoDB.DocumentClient();
const TABLE_NAME = process.env.USERS_TABLE;

// Rate limiting configuration
const RATE_LIMIT_WINDOW = 60 * 1000; // 1 minute
const MAX_REQUESTS_PER_IP = 5;
const MAX_REQUESTS_PER_EMAIL = 3;

// In-memory store for rate limiting (use DynamoDB or ElastiCache for production multi-instance)
const rateLimitStore = new Map();

function getRateLimitKey(type, identifier) {
  return `${type}:${identifier}`;
}

function checkRateLimit(type, identifier, maxRequests) {
  const key = getRateLimitKey(type, identifier);
  const now = Date.now();
  
  if (!rateLimitStore.has(key)) {
    rateLimitStore.set(key, { count: 1, resetTime: now + RATE_LIMIT_WINDOW });
    return true;
  }
  
  const record = rateLimitStore.get(key);
  
  if (now > record.resetTime) {
    rateLimitStore.set(key, { count: 1, resetTime: now + RATE_LIMIT_WINDOW });
    return true;
  }
  
  if (record.count >= maxRequests) {
    return false;
  }
  
  record.count++;
  return true;
}

function cleanupExpiredEntries() {
  const now = Date.now();
  for (const [key, value] of rateLimitStore.entries()) {
    if (now > value.resetTime) {
      rateLimitStore.delete(key);
    }
  }
}

function validateEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email) && email.length <= 254;
}

function validatePassword(password) {
  return password && 
         password.length >= 8 && 
         password.length <= 128 &&
         /[A-Z]/.test(password) &&
         /[a-z]/.test(password) &&
         /[0-9]/.test(password) &&
         /[^A-Za-z0-9]/.test(password);
}

function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return { salt, hash };
}

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  return input.trim().substring(0, 1000);
}

exports.handler = async (event) => {
  // Cleanup expired rate limit entries periodically
  if (Math.random() < 0.1) {
    cleanupExpiredEntries();
  }

  const headers = {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Cache-Control': 'no-store, no-cache, must-revalidate, private'
  };

  try {
    // Extract IP address for rate limiting
    const sourceIp = event.requestContext?.identity?.sourceIp || 'unknown';
    
    // Check IP-based rate limit
    if (!checkRateLimit('ip', sourceIp, MAX_REQUESTS_PER_IP)) {
      return {
        statusCode: 429,
        headers,
        body: JSON.stringify({ 
          error: 'Too many requests from this IP address. Please try again later.' 
        })
      };
    }

    // Parse and validate request body
    let body;
    try {
      body = JSON.parse(event.body || '{}');
    } catch (e) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Invalid JSON in request body' })
      };
    }

    const email = sanitizeInput(body.email).toLowerCase();
    const password = body.password;

    // Validate email
    if (!validateEmail(email)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Invalid email format' })
      };
    }

    // Check email-based rate limit
    if (!checkRateLimit('email', email, MAX_REQUESTS_PER_EMAIL)) {
      return {
        statusCode: 429,
        headers,
        body: JSON.stringify({ 
          error: 'Too many registration attempts for this email. Please try again later.' 
        })
      };
    }

    // Validate password
    if (!validatePassword(password)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ 
          error: 'Password must be 8-128 characters and contain uppercase, lowercase, number, and special character' 
        })
      };
    }

    // Check if user already exists
    const existingUser = await dynamodb.get({
      TableName: TABLE_NAME,
      Key: { email }
    }).promise();

    if (existingUser.Item) {
      // Return same response as successful registration to prevent email enumeration
      return {
        statusCode: 200,
        headers,
        body: JSON.stringify({ 
          message: 'Registration successful. Please check your email for verification.' 
        })
      };
    }

    // Hash password
    const { salt, hash } = hashPassword(password);

    // Create user record
    const userId = crypto.randomUUID();
    const timestamp = new Date().toISOString();

    await dynamodb.put({
      TableName: TABLE_NAME,
      Item: {
        email,
        userId,
        passwordHash: hash,
        passwordSalt: salt,
        createdAt: timestamp,
        verified: false,
        accountLocked: false,
        failedLoginAttempts: 0
      },
      ConditionExpression: 'attribute_not_exists(email)'
    }).promise();

    return {
      statusCode: 200,
      headers,
      body: JSON.stringify({ 
        message: 'Registration successful. Please check your email for verification.',
        userId 
      })
    };

  } catch (error) {
    console.error('Registration error:', error);

    // Don't expose internal error details
    if (error.code === 'ConditionalCheckFailedException') {
      return {
        statusCode: 200,
        headers,
        body: JSON.stringify({ 
          message: 'Registration successful. Please check your email for verification.' 
        })
      };
    }

    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ error: 'An error occurred during registration. Please try again.' })
    };
  }
};